// // This module decodes a 16-bit scancode input to generate control signals for directional movement.
// Depending on the specific scancode values (e.g., for left, down, right, and up), the module outputs a low signal on the corresponding direction output while ensuring all other direction outputs remain high.
module top_module(
    input [15:0] scancode,
    output reg left,
    output reg down,
    output reg right,
    output reg up  );always @(*) begin
        up = 1'b0; down = 1'b0; left = 1'b0; right = 1'b0;
        case (scancode)
            16'he06b: left = 1'b1;
            16'he072: down = 1'b1;
            16'he074: right = 1'b1;
            16'he075: up = 1'b1;
        endcase
    end


endmodule
